"""Steel panel geometry."""

import math
from typing import Optional

from fhecor_structuralcodes.core._panel_results import StiffenedPanelBucklingResults
from fhecor_structuralcodes.geometry._long_stiffener import Long_stiffener
from fhecor_structuralcodes.geometry._plate import Plate, PlatePosition, Point2D, assemble_inertia
from fhecor_structuralcodes.materials import Structural_steel


class Panel:
    """
    Steel Panel of thin walled section.

    Args:
        b: width of the panel in mm (float)
        t: thickness of the panel in mm (float)
        material: material of the panel (Structural_steel)
        long_stiffeners: lista de tuplas (s, Long_stiffener) donde *s* es la
            coordenada-abscisa a lo largo del eje del panel en la que se
            sitúa el rigidizador.  Las chapas de cada rigidizador se definen
            en el sistema local del rigidizador; al acceder a la propiedad
            ``long_stiffeners`` se obtienen ya transformadas al sistema
            global del panel.
        shear_distribution_factor: factor de distribución del alma a
            cortante. Para dos almas simétricas vale 1.
        torsion_distribution_factor: factor de distribución del panel
            a torsión (mismo concepto que shear_distribution_factor).
        a: separación de rigidizadores transversales en mm (float)
        y0: coordenada y global del extremo 1 del panel en mm [+ →]
        z0: coordenada z global del extremo 1 del panel en mm [+ ↑]
        alfa: ángulo del panel en grados respecto a la horizontal
            [+ sentido antihorario]
    """

    def __init__(
        self,
        b: float,
        t: float,
        material: Structural_steel,
        long_stiffeners: Optional[list[tuple[float, Long_stiffener]]] = None,
        shear_distribution_factor: float = 1,
        torsion_distribution_factor: float = 1,
        a: float = 10000,
        y0: float = 0,
        z0: float = 0,
        alfa: float = 0,
    ):
        self.b = b
        self.t = t
        self.material = material
        self._long_stiffeners = long_stiffeners or []
        self.shear_distribution_factor = shear_distribution_factor
        self.torsion_distribution_factor = torsion_distribution_factor
        self.a = a
        self.y0 = y0
        self.z0 = z0
        self.alfa = alfa
        self._analysis_plates: Optional[list[Plate]] = None

        # Resultados de abolladura de panel rigidizado (EN 1993-1-5 §4.5).
        # Nulos hasta que se llame a compute_stiffened_panel_buckling().
        self._stiffened_panel_buckling_results: Optional[
            StiffenedPanelBucklingResults
        ] = None

    # ------------------------------------------------------------------
    # Geometría del eje del panel
    # ------------------------------------------------------------------

    @property
    def endpoints(self) -> tuple[Point2D, Point2D]:
        """Start and end points of the panel axis in global coordinates."""
        start = (self.y0, self.z0)
        end = Plate.segment_end(self.y0, self.z0, self.b, self.alfa)
        return start, end

    @property
    def direction(self) -> Point2D:
        """Unit direction vector of the panel in the global y-z plane."""
        alpha = math.radians(self.alfa)
        return math.cos(alpha), math.sin(alpha)

    def abscissa_at(self, point: Point2D) -> float:
        """Project a point onto the panel axis and return its signed abscissa."""
        start, _ = self.endpoints
        dir_y, dir_z = self.direction
        return (point[0] - start[0]) * dir_y + (point[1] - start[1]) * dir_z

    # ------------------------------------------------------------------
    # Transformación de rigidizadores al sistema global del panel
    # ------------------------------------------------------------------

    def _transform_stiffener(
        self, s: float, stiffener: Long_stiffener
    ) -> Long_stiffener:
        """Transforma un rigidizador del sistema local al global del panel.

        El origen del rigidizador se sitúa en la coordenada *s* del panel y
        sus ejes locales se rotan según *alfa* del panel:

        - eje-y local del rigidizador → dirección s del panel  (alfa)
        - eje-z local del rigidizador → normal al panel        (alfa + 90°)
        """
        alpha = math.radians(self.alfa)
        cos_a = math.cos(alpha)
        sin_a = math.sin(alpha)
        origin_y = self.y0 + s * cos_a - 0.5 * self.t * sin_a
        origin_z = self.z0 + s * sin_a + 0.5 * self.t * cos_a

        transformed: list[Plate] = []
        for ch in stiffener.plates:
            y0_g = origin_y + ch.y0 * cos_a - ch.z0 * sin_a
            z0_g = origin_z + ch.y0 * sin_a + ch.z0 * cos_a
            transformed.append(
                Plate(
                    material=ch.material,
                    b=ch.b,
                    t=ch.t,
                    y0=y0_g,
                    z0=z0_g,
                    alfa=ch.alfa + self.alfa,
                    non_buckling=ch.non_buckling,
                    plate_position=ch.plate_position,
                )
            )
        return Long_stiffener(plates=transformed)

    @property
    def long_stiffeners(self) -> list[Long_stiffener]:
        """Rigidizadores transformados al sistema global del panel."""
        return [self._transform_stiffener(s, st) for s, st in self._long_stiffeners]

    # ------------------------------------------------------------------
    # Sub-placas del panel
    # ------------------------------------------------------------------

    @staticmethod
    def _stiffener_cut_offsets(stiffener: Long_stiffener) -> list[float]:
        """Devuelve los offsets en *y* local del rigidizador donde sus
        chapas cruzan z=0 (la superficie del panel).

        Para chapas inclinadas calcula la intersección exacta.
        Para chapas horizontales en z≈0, toma ambos extremos.
        """
        offsets: list[float] = []
        tol = 1e-6
        for ch in stiffener.plates:
            alpha_ch = math.radians(ch.alfa)
            sin_a = math.sin(alpha_ch)
            cos_a = math.cos(alpha_ch)

            z_start = ch.z0
            z_end = ch.z0 + ch.b * sin_a
            z_min = min(z_start, z_end)
            z_max = max(z_start, z_end)

            if z_min > tol or z_max < -tol:
                continue

            if abs(sin_a) > tol:
                s_at_z0 = -ch.z0 / sin_a
                if -tol <= s_at_z0 <= ch.b + tol:
                    y_at_z0 = ch.y0 + s_at_z0 * cos_a
                    offsets.append(y_at_z0)
            else:
                if abs(ch.z0) <= tol:
                    offsets.append(ch.y0)
                    offsets.append(ch.y0 + ch.b)
        return offsets

    def _build_base_plates(self) -> list[Plate]:
        """Divide el panel en sub-placas internas en los puntos donde
        los rigidizadores cruzan z=0 en su sistema local.

        Para cada rigidizador en la posición *s_i*, se analizan sus
        chapas buscando intersecciones con z=0 (superficie del panel).
        Cada intersección genera un punto de corte en el panel a la
        coordenada ``s_i + y_offset``.

        Cada sub-placa hereda *alfa* del panel y su origen (y0, z0)
        se obtiene proyectando la coordenada-s desde el origen del panel:

            y0 = panel.y0 + s * cos(alfa)
            z0 = panel.z0 + s * sin(alfa)
        """
        plates: list[Plate] = []
        alpha = math.radians(self.alfa)
        cos_a = math.cos(alpha)
        sin_a = math.sin(alpha)

        if not self._long_stiffeners:
            plates.append(
                Plate(
                    material=self.material,
                    b=self.b,
                    t=self.t,
                    y0=self.y0,
                    z0=self.z0,
                    alfa=self.alfa,
                )
            )
        else:
            all_cuts: list[float] = []
            for s_i, st in self._long_stiffeners:
                for y_off in self._stiffener_cut_offsets(st):
                    all_cuts.append(s_i + y_off)

            cut_points = sorted(set(round(s, 6) for s in all_cuts))
            cut_points = [s for s in cut_points if 0 < s < self.b]
            boundaries = [0.0] + cut_points + [float(self.b)]

            for i in range(len(boundaries) - 1):
                s_start = boundaries[i]
                width = boundaries[i + 1] - s_start
                if i == 0:
                    plate_position: PlatePosition = "end_supported_edge"
                elif i == len(boundaries) - 2:
                    plate_position = "start_supported_edge"
                else:
                    plate_position = "internal"
                if width > 0:
                    plates.append(
                        Plate(
                            material=self.material,
                            b=width,
                            t=self.t,
                            y0=self.y0 + s_start * cos_a,
                            z0=self.z0 + s_start * sin_a,
                            alfa=self.alfa,
                            plate_position=plate_position,
                        )
                    )

        return plates

    @property
    def base_plates(self) -> list[Plate]:
        """Sub-placas base del panel (sin rigidizadores)."""
        return self._build_base_plates()

    def _build_analysis_plates(self) -> list[Plate]:
        """Builds a stable snapshot of all plates used in section analysis."""
        result: list[Plate] = list(self.base_plates)
        for st in self.long_stiffeners:
            result.extend(st.plates)
        self._analysis_plates = result
        return result

    def set_analysis_plates_from_base(self, base_plates: list[Plate]) -> None:
        """Set analysis snapshot from base plates and transformed stiffeners."""
        result: list[Plate] = list(base_plates)
        for st in self.long_stiffeners:
            result.extend(st.plates)
        self._analysis_plates = result

    @property
    def analysis_plates(self) -> list[Plate]:
        """Stable plate snapshot used by section-level analysis."""
        if self._analysis_plates is None:
            return self._build_analysis_plates()
        return self._analysis_plates

    # ------------------------------------------------------------------
    # Resultados de abolladura de panel rigidizado (EN 1993-1-5 §4.5)
    # ------------------------------------------------------------------

    @property
    def stiffened_panel_buckling_results(
        self,
    ) -> Optional[StiffenedPanelBucklingResults]:
        """
        Resultados del análisis de abolladura del panel rigidizado.

        Es ``None`` hasta que se llame a :meth:`compute_stiffened_panel_buckling`.
        """
        return self._stiffened_panel_buckling_results

    def compute_stiffened_panel_buckling(
        self,
        *args,
    ) -> Optional[StiffenedPanelBucklingResults]:
        """
        Calcula la abolladura del panel rigidizado según EN 1993-1-5 §4.5.

        Almacena el resultado en :attr:`stiffened_panel_buckling_results` y lo
        devuelve.

        Raises:
            NotImplementedError: La implementación está pendiente.
        """
        raise NotImplementedError(
            "compute_stiffened_panel_buckling: implementación pendiente"
        )

    # ------------------------------------------------------------------
    # Propiedades geométricas e inercias
    # ------------------------------------------------------------------

    @property
    def _all_plates(self) -> list[Plate]:
        """Todas las chapas del panel: sub-placas + chapas de rigidizadores."""
        result: list[Plate] = list(self.base_plates)
        for st in self.long_stiffeners:
            result.extend(st.plates)
        return result

    @property
    def area(self) -> float:
        """Área total del panel (sub-placas + rigidizadores) en mm²."""
        return sum(p.area for p in self._all_plates)

    @property
    def centroid(self) -> tuple[float, float]:
        """Centroide del panel (yc, zc) en ejes globales, mm."""
        plates = self._all_plates
        if not plates:
            return self.y0, self.z0
        A_tot = sum(p.area for p in plates)
        yc = sum(p.area * p.centroid[0] for p in plates) / A_tot
        zc = sum(p.area * p.centroid[1] for p in plates) / A_tot
        return yc, zc

    def inertia_at_origin(self) -> tuple[float, float, float]:
        """Inercias (Iyy, Izz, Iyz) respecto a (y0, z0) del panel, mm⁴."""
        return assemble_inertia(
            self._all_plates,
            y_ref=self.y0,
            z_ref=self.z0,
        )

    def inertia_at_cg(self) -> tuple[float, float, float]:
        """Inercias (Iyy, Izz, Iyz) respecto al centroide del panel, mm⁴."""
        yc, zc = self.centroid
        return assemble_inertia(
            self._all_plates,
            y_ref=yc,
            z_ref=zc,
        )

    @property
    def Iyy_origin(self) -> float:
        """Iyy respecto a (y0, z0), mm⁴."""
        return self.inertia_at_origin()[0]

    @property
    def Izz_origin(self) -> float:
        """Izz respecto a (y0, z0), mm⁴."""
        return self.inertia_at_origin()[1]

    @property
    def Iyz_origin(self) -> float:
        """Iyz respecto a (y0, z0), mm⁴."""
        return self.inertia_at_origin()[2]

    @property
    def Iyy_cg(self) -> float:
        """Iyy respecto al CG del panel, mm⁴."""
        return self.inertia_at_cg()[0]

    @property
    def Izz_cg(self) -> float:
        """Izz respecto al CG del panel, mm⁴."""
        return self.inertia_at_cg()[1]

    @property
    def Iyz_cg(self) -> float:
        """Iyz respecto al CG del panel, mm⁴."""
        return self.inertia_at_cg()[2]

    # ------------------------------------------------------------------
    # Otras propiedades geométricas
    # ------------------------------------------------------------------

    def _get_d(self) -> float:
        """Profundidad vertical proyectada del panel (mm)."""
        alfa_rad = math.radians(self.alfa)
        return self.b * math.cos(alfa_rad)

    @property
    def d(self) -> float:
        """Profundidad vertical proyectada del panel (mm)."""
        return self._get_d()

    def _get_I_sl(self) -> float:
        """Momento de inercia de todos los rigidizadores del panel."""
        return sum(st.Iyy for _, st in self._long_stiffeners)

    @property
    def I_sl(self) -> float:
        """Momento de inercia de los rigidizadores del panel."""
        return self._get_I_sl()

    @property
    def properties(self) -> float:
        """mechanical properties of the panel."""
        prop = []
        prop.append(f"Area: {self.area*1e-2:.0f} cm²")
        prop.append(
            f"Centroid: {self.centroid[0]/10:.2f} cm, {self.centroid[1]/10:.2f} cm"
        )
        prop.append(f"Iyy: {self.Iyy_origin*1e-4:.0f} cm⁴")
        prop.append(f"Izz: {self.Izz_origin*1e-4:.0f} cm⁴")
        prop.append(f"Iyz: {self.Iyz_origin*1e-4:.0f} cm⁴")
        prop.append(f"I_sl: {self.I_sl*1e-4:.0f} cm⁴")
        prop.append(f"Iyy_cg: {self.Iyy_cg*1e-4:.0f} cm⁴")
        prop.append(f"Izz_cg: {self.Izz_cg*1e-4:.0f} cm⁴")
        prop.append(f"Iyz_cg: {self.Iyz_cg*1e-4:.0f} cm⁴")
        text = "\n".join(prop)
        return text
